prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "3c1c7ac2bf4042fe9cd4ed34ce14a188" .
  OPTIONAL { ?model bbo:name ?modelName . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?pathExists WHERE {
  BIND(<https://www.teamingai-project.eu/kg/process/qualityInspection/sid-59E2CFCD-9D63-49A7-ACD4-BFC6A59E71ED> AS ?startTask)
  BIND(<https://www.teamingai-project.eu/kg/process/qualityInspection/sid-C57DC0A3-EED2-48A4-A208-AB2FC780F555> AS ?endTask)

  {
    SELECT (COUNT(*) > 0 AS ?pathExists) WHERE {
      ?startTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?endTask .
    }
  }
}
